import React from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import Home from './pages/Home';
import Login from './pages/Login';

function App() {
  const bgStyle = {
    backgroundImage: `linear-gradient(rgba(255,255,255,0.6), rgba(255,255,255,0.6)), url('https://images.unsplash.com/photo-1586528116311-ad8dd3c8310d?q=80&w=2000')`,
    backgroundSize: 'cover',
    backgroundPosition: 'center',
    backgroundAttachment: 'fixed',
    minHeight: '100vh',
    fontFamily: 'sans-serif'
  };

  return (
    <Router>
      <div style={bgStyle}>
        {/* Professional Navbar */}
        <nav style={{ backgroundColor: '#0056b3', padding: '15px 50px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', boxShadow: '0 4px 15px rgba(0,0,0,0.2)' }}>
          <Link to="/" style={{ color: 'white', textDecoration: 'none', fontWeight: 'bold', fontSize: '26px' }}>APNI MANZIL</Link>
          <Link to="/login" style={{ backgroundColor: '#28a745', color: 'white', padding: '10px 30px', borderRadius: '30px', textDecoration: 'none', fontWeight: 'bold' }}>Login / Join</Link>
        </nav>

        {/* Navigation Routes */}
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/login" element={<Login />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
